import pytest
from sequence import Sequence, SequenceGroup, SequenceStatus
from block_manager import BlockSpaceManager, PhysicalBlock

BLOCK_SIZE = 4
NUM_BLOCKS = 16


def make_seq(seq_id: int, prompt_len: int, block_size: int = BLOCK_SIZE) -> Sequence:
    return Sequence(seq_id, list(range(prompt_len)), block_size)


def make_group(seq_id: int, prompt_len: int) -> SequenceGroup:
    seq = make_seq(seq_id, prompt_len)
    return SequenceGroup(request_id=f"req-{seq_id}", seqs=[seq])


# ------------------------------------------------------------------ #
# 1. Basic allocate / free                                           #
# ------------------------------------------------------------------ #

class TestAllocateFree:
    def test_allocate_consumes_blocks(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=7)   # 7 tokens → ceil(7/4)=2 blocks
        assert bsm.can_allocate(group)
        bsm.allocate(group)
        assert bsm.num_free_blocks == NUM_BLOCKS - 2

    def test_free_returns_blocks(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=7)
        bsm.allocate(group)
        seq = group.get_seqs()[0]
        bsm.free(seq)
        assert bsm.num_free_blocks == NUM_BLOCKS

    def test_status_becomes_running_after_allocate(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=4)
        bsm.allocate(group)
        assert group.get_seqs()[0].status == SequenceStatus.RUNNING

    def test_block_table_length_matches_logical_blocks(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        for prompt_len in [1, 4, 5, 8, 9]:
            group = make_group(prompt_len, prompt_len)
            bsm.allocate(group)
            seq = group.get_seqs()[0]
            assert len(bsm.get_block_table(seq)) == seq.num_logic_blocks
            bsm.free(seq)


