class TestOOM:
    def test_can_allocate_false_when_not_enough_blocks(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, num_gpu_blocks=2)
        group = make_group(0, prompt_len=9)  # requires 3 blocks
        assert not bsm.can_allocate(group)

    def test_allocate_raises_on_oom(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, num_gpu_blocks=1)
        group = make_group(0, prompt_len=9)
        with pytest.raises(MemoryError):
            bsm.allocate(group)  # can_allocate returns False; forcing allocate should raise

    def test_can_append_slot_false_when_full(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, num_gpu_blocks=2)
        group = make_group(0, prompt_len=8)  # exactly 2 blocks used
        bsm.allocate(group)
        assert bsm.num_free_blocks == 0
        assert not bsm.can_append_slot(group)


