# 3. append_slot: block expansion during decode                      #
# ------------------------------------------------------------------ #

class TestAppendSlot:
    def test_no_new_block_needed_within_existing_block(self):
        """prompt=5 tokens → 2 blocks; the 6th token still fits inside the 2nd block"""
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=5)
        bsm.allocate(group)
        seq = group.get_seqs()[0]
        free_before = bsm.num_free_blocks

        seq.append_token_id(999)
        cow = bsm.append_slot(seq)

        assert cow is None
        assert bsm.num_free_blocks == free_before  # no new block allocated

    def test_new_block_allocated_when_block_full(self):
        """prompt=8 tokens → 2 full blocks; decoding the 9th token requires a new block"""
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=8)
        bsm.allocate(group)
        seq = group.get_seqs()[0]
        free_before = bsm.num_free_blocks

        seq.append_token_id(999)
        cow = bsm.append_slot(seq)

        assert cow is None
        assert bsm.num_free_blocks == free_before - 1
        assert len(bsm.get_block_table(seq)) == 3

    def test_multiple_decode_steps(self):
        """Decode 12 steps consecutively; blocks expand on demand"""
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=3)
        bsm.allocate(group)
        seq = group.get_seqs()[0]

        for i in range(12):
            seq.append_token_id(i)
            bsm.append_slot(seq)

        # 3+12=15 tokens → ceil(15/4)=4 blocks
        assert len(bsm.get_block_table(seq)) == 4


