# 4. fork + Copy-on-Write                                             #
# ------------------------------------------------------------------ #

class TestForkAndCoW:
    def test_fork_shares_blocks(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=8)
        bsm.allocate(group)
        parent = group.get_seqs()[0]

        child = make_seq(seq_id=1, prompt_len=8)
        child.status = SequenceStatus.RUNNING
        free_before = bsm.num_free_blocks

        bsm.fork(parent, child)

        # fork does not consume additional physical blocks
        assert bsm.num_free_blocks == free_before
        # block_table entries point to the same physical block objects (shared)
        assert bsm.get_block_table(parent) == bsm.get_block_table(child)

    def test_cow_triggers_on_shared_write(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        # last block has 1 token and 3 empty slots; decode will not allocate a new block
        group = make_group(0, prompt_len=5)
        bsm.allocate(group)
        parent = group.get_seqs()[0]

        child = make_seq(seq_id=1, prompt_len=5)
        child.status = SequenceStatus.RUNNING
        bsm.fork(parent, child)

        free_before = bsm.num_free_blocks

        # parent decodes one step → last block ref_count=2 → CoW triggered
        parent.append_token_id(100)
        cow = bsm.append_slot(parent)

        assert cow is not None                  # CoW was triggered
        old_num, new_num = cow
        assert old_num != new_num
        assert bsm.num_free_blocks == free_before - 1  # one extra block allocated

        # child block_table still points to the old block
        child_table = bsm.get_block_table(child)
        parent_table = bsm.get_block_table(parent)
        assert child_table[-1] == old_num
        assert parent_table[-1] == new_num

    def test_free_after_fork_decrements_refcount(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=4)
        bsm.allocate(group)
        parent = group.get_seqs()[0]

        child = make_seq(seq_id=1, prompt_len=4)
        child.status = SequenceStatus.RUNNING
        bsm.fork(parent, child)

        # free parent: shared block ref_count drops from 2 to 1; should not return to pool yet
        bsm.free(parent)
        free_after_parent_free = bsm.num_free_blocks

        # free child: ref_count reaches 0; block is now returned to pool
        bsm.free(child)
        assert bsm.num_free_blocks == free_after_parent_free + 1


