class TestFullLifecycle:
    def test_allocate_decode_free_restores_pool(self):
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        initial_free = bsm.num_free_blocks

        group = make_group(0, prompt_len=6)
        bsm.allocate(group)
        seq = group.get_seqs()[0]

        for i in range(20):
            seq.append_token_id(i)
            bsm.append_slot(seq)

        bsm.free(seq)
        assert bsm.num_free_blocks == initial_free   # all blocks fully returned

    def test_block_table_values_are_valid_indices(self):
        """Physical block indices must be within valid range; an out-of-bounds index passed to the kernel will cause undefined behaviour."""
        bsm = BlockSpaceManager(BLOCK_SIZE, NUM_BLOCKS)
        group = make_group(0, prompt_len=3)
        bsm.allocate(group)
        seq = group.get_seqs()[0]

        for i in range(10):
            seq.append_token_id(i)
            bsm.append_slot(seq)

        table = bsm.get_block_table(seq)
        for idx in table:
            assert 0 <= idx < NUM_BLOCKS